args.sparql:
SELECT ?attendance
WHERE {
  VALUES ?seriesLabels {
    "2018 World Series"
    "2013 American League Championship Series"
    "1975 American League Championship Series"
  }
  ?series rdfs:label ?seriesLabels .
  FILTER (LANG(?seriesLabels) = 'en')
  ?game wdt:P154 ?series .
  { ?game wdt:P150 wd:Q3035 }
  UNION
  { ?game wdt:P151 wd:Q3035 }
  ?game wdt:P2787 ?attendance .
}
ORDER BY ?attendance
OFFSET 4
LIMIT 1

